using NP phigrOS;
int a[1000005];
signed main(){
	int t;
	for(cin>>t;t--;){
		vector<int> v1,v2;
		int n;
		cin>>n;
		for(int i=1;i<=n;i++){
			char c;cin>>c;
			a[i]=c-'0';
		}
		v1.push_back(0),v2.push_back(0);
		for(int i=1;i<=n;i++){
			if(a[i]==1) v1.push_back(i);
			else v2.push_back(i);
		}
		int sum1=0,sum2=0;
		for(int i=1;i<v1.size();i++){
			int k=v1[i]-(v1.size()-1-i);
			if(k<1) sum1++;
			else sum1+=k;
		}
		for(int i=1;i<v2.size();i++){
			int k=v2[i]-(v2.size()-1-i);
			if(k<1) sum2++;
			else sum2+=k;
		}
		cout<<min(sum1,sum2)<<endl;
	}
	return 0;
}
